      c: {
        code: `#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int longestCommonSubsequence(char* text1, char* text2) {
    int m = (int)strlen(text1), n = (int)strlen(text2);
    int* prev = (int*)calloc(n + 1, sizeof(int));
    int* curr = (int*)calloc(n + 1, sizeof(int));
    for (int i = 1; i <= m; i++) {
        for (int j = 1; j <= n; j++) {
            if (text1[i - 1] == text2[j - 1]) {
                curr[j] = prev[j - 1] + 1;
            } else {
                curr[j] = prev[j] > curr[j - 1] ? prev[j] : curr[j - 1];
            }
        }
        int* tmp = prev;
        prev = curr;
        curr = tmp;
        memset(curr, 0, (n + 1) * sizeof(int));
    }
    int result = prev[n];
    free(prev);
    free(curr);
    return result;
}`,
        complexity: { time: 'O(m*n)', space: 'O(n)' },
        approach: 'Two rolling rows instead of a full m+1 x n+1 table. Swap pointers after each row and reset the new working row to zero.',
      },
