  'merge-k-sorted-lists': {
    tags: ['linked-list', 'divide-and-conquer', 'heap', 'merge-sort'],
    companies: ['amazon', 'meta', 'microsoft', 'google', 'apple', 'bloomberg'],
    viz: mergeKListsViz(),
    solutions: {
      python: {
        code: `import heapq

class Solution:
    def mergeKLists(self, lists):
        heap = []
        for i, lst in enumerate(lists):
            if lst:
                heapq.heappush(heap, (lst[0], i, 0))
        out = []
        while heap:
            val, i, j = heapq.heappop(heap)
            out.append(val)
            if j + 1 < len(lists[i]):
                heapq.heappush(heap, (lists[i][j + 1], i, j + 1))
        return out`,
        complexity: { time: 'O(N log k)', space: 'O(k)' },
        approach: 'DB stores each input as a List[List[int]] (k flat arrays), so the solution iterates indices instead of ListNode pointers. Tuple (value, listIndex, positionInList) keeps the heap strictly ordered even when values tie. Output is a flat sorted list.',
      },
      javascript: {
        code: `function mergeKLists(lists) {
  const heap = [];
  const swap = (a, b) => { [heap[a], heap[b]] = [heap[b], heap[a]]; };
  const up = (i) => {
    while (i > 0) {
      const p = (i - 1) >> 1;
      if (heap[p][0] <= heap[i][0]) break;
      swap(p, i); i = p;
    }
  };
  const down = (i) => {
    const n = heap.length;
    while (true) {
      const l = 2 * i + 1, r = l + 1;
      let m = i;
      if (l < n && heap[l][0] < heap[m][0]) m = l;
      if (r < n && heap[r][0] < heap[m][0]) m = r;
      if (m === i) break;
      swap(m, i); i = m;
    }
  };
  for (let i = 0; i < lists.length; i++) {
    if (lists[i].length) {
      heap.push([lists[i][0], i, 0]);
      up(heap.length - 1);
    }
  }
  const out = [];
  while (heap.length) {
    const [val, i, j] = heap[0];
    out.push(val);
    if (j + 1 < lists[i].length) {
      heap[0] = [lists[i][j + 1], i, j + 1];
      down(0);
    } else {
      const last = heap.pop();
      if (heap.length) { heap[0] = last; down(0); }
    }
  }
  return out;
}`,
        complexity: { time: 'O(N log k)', space: 'O(k)' },
        approach: 'JS has no built-in heap, so a hand-rolled binary min-heap of (value, listIdx, posInList) tuples. Popping replaces the root with either the next node in the same list or the heap tail — both followed by a single sift-down for O(log k).',
      },
      java: {
        code: `import java.util.*;

class Solution {
    public List<Integer> mergeKLists(List<List<Integer>> lists) {
        PriorityQueue<int[]> heap = new PriorityQueue<>((a, b) -> Integer.compare(a[0], b[0]));
        for (int i = 0; i < lists.size(); i++) {
            if (!lists.get(i).isEmpty()) {
                heap.offer(new int[]{ lists.get(i).get(0), i, 0 });
            }
        }
        List<Integer> out = new ArrayList<>();
        while (!heap.isEmpty()) {
            int[] top = heap.poll();
            int val = top[0], i = top[1], j = top[2];
            out.add(val);
            if (j + 1 < lists.get(i).size()) {
                heap.offer(new int[]{ lists.get(i).get(j + 1), i, j + 1 });
            }
        }
        return out;
    }
}`,
        complexity: { time: 'O(N log k)', space: 'O(k)' },
        approach: 'PriorityQueue keyed by value handles the heap. int[] tuple of (value, listIdx, posInList) avoids autoboxing into Integer for the indices. Heap size stays <= k throughout.',
      },
      cpp: {
        code: `#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    vector<int> mergeKLists(vector<vector<int>>& lists) {
        using T = tuple<int, int, int>; // (value, listIdx, posInList)
        priority_queue<T, vector<T>, greater<T>> heap;
        for (int i = 0; i < (int)lists.size(); ++i) {
            if (!lists[i].empty()) heap.emplace(lists[i][0], i, 0);
        }
        vector<int> out;
        while (!heap.empty()) {
            auto [val, i, j] = heap.top(); heap.pop();
            out.push_back(val);
            if (j + 1 < (int)lists[i].size()) {
                heap.emplace(lists[i][j + 1], i, j + 1);
            }
        }
        return out;
    }
};`,
        complexity: { time: 'O(N log k)', space: 'O(k)' },
        approach: 'std::priority_queue with greater<T> flips it into a min-heap. Structured bindings unpack the tuple cleanly. emplace constructs in place — no temporary tuple objects.',
      },
      c: {
        code: `#include <stdio.h>
#include <stdlib.h>
#include <string.h>

// DB encodes input as List[List[int]] (k flat arrays). The harness shape
// does not give us ListNode* heads, so this returns a flat sorted int*
// instead of a ListNode chain.
typedef struct { int val; int listIdx; int pos; } HeapEntry;

static void heap_swap(HeapEntry* a, HeapEntry* b) { HeapEntry t = *a; *a = *b; *b = t; }

static void sift_up(HeapEntry* h, int i) {
    while (i > 0) {
        int p = (i - 1) / 2;
        if (h[p].val <= h[i].val) break;
        heap_swap(&h[p], &h[i]); i = p;
    }
}

static void sift_down(HeapEntry* h, int n, int i) {
    while (1) {
        int l = 2 * i + 1, r = l + 1, m = i;
        if (l < n && h[l].val < h[m].val) m = l;
        if (r < n && h[r].val < h[m].val) m = r;
        if (m == i) break;
        heap_swap(&h[m], &h[i]); i = m;
    }
}

int* mergeKLists(int** lists, int listsSize, int* listsColSize, int* returnSize) {
    int total = 0;
    for (int i = 0; i < listsSize; i++) total += listsColSize[i];
    HeapEntry* heap = (HeapEntry*)malloc(sizeof(HeapEntry) * (listsSize + 1));
    int* pos = (int*)calloc(listsSize, sizeof(int));
    int hsz = 0;
    for (int i = 0; i < listsSize; i++) {
        if (listsColSize[i] > 0) {
            heap[hsz++] = (HeapEntry){ lists[i][0], i, 0 };
            sift_up(heap, hsz - 1);
        }
    }
    int* out = (int*)malloc(sizeof(int) * (total > 0 ? total : 1));
    int o = 0;
    while (hsz > 0) {
        HeapEntry top = heap[0];
        out[o++] = top.val;
        pos[top.listIdx] = top.pos + 1;
        if (pos[top.listIdx] < listsColSize[top.listIdx]) {
            heap[0] = (HeapEntry){ lists[top.listIdx][pos[top.listIdx]], top.listIdx, pos[top.listIdx] };
        } else {
            heap[0] = heap[--hsz];
        }
        if (hsz > 0) sift_down(heap, hsz, 0);
    }
    free(heap); free(pos);
    *returnSize = o;
    return out;
}`,
        complexity: { time: 'O(N log k)', space: 'O(k)' },
        approach: 'Hand-rolled binary heap of (value, listIdx, posInList). The C harness passes lists as int** + int* listsColSize, so we iterate by index instead of node pointer. Caller owns the returned malloc.',
      },
      go: {
        code: `import "container/heap"

type entry struct {
    val, listIdx, pos int
}

type minHeap []entry

func (h minHeap) Len() int            { return len(h) }
func (h minHeap) Less(i, j int) bool  { return h[i].val < h[j].val }
func (h minHeap) Swap(i, j int)       { h[i], h[j] = h[j], h[i] }
func (h *minHeap) Push(x interface{}) { *h = append(*h, x.(entry)) }
func (h *minHeap) Pop() interface{}   { old := *h; n := len(old); x := old[n-1]; *h = old[:n-1]; return x }

func mergeKLists(lists [][]int) []int {
    h := &minHeap{}
    heap.Init(h)
    for i, lst := range lists {
        if len(lst) > 0 {
            heap.Push(h, entry{lst[0], i, 0})
        }
    }
    out := []int{}
    for h.Len() > 0 {
        top := heap.Pop(h).(entry)
        out = append(out, top.val)
        if top.pos+1 < len(lists[top.listIdx]) {
            heap.Push(h, entry{lists[top.listIdx][top.pos+1], top.listIdx, top.pos + 1})
        }
    }
    return out
}`,
        complexity: { time: 'O(N log k)', space: 'O(k)' },
        approach: 'container/heap requires implementing the heap.Interface methods. Less compares the value field — that is what makes it a min-heap. Heap.Push / heap.Pop call our Push / Pop after sift-up / sift-down respectively.',
      },
    },
  },
