        code: `class Solution {
    static class Node {
        Node[] kids = new Node[26];
        String word;
    }

    public List<String> findWords(char[][] board, String[] words) {
        Node root = new Node();
        for (String w : words) {
            Node node = root;
            for (char ch : w.toCharArray()) {
                int i = ch - 'a';
                if (node.kids[i] == null) node.kids[i] = new Node();
                node = node.kids[i];
            }
            node.word = w;
        }
        List<String> found = new ArrayList<>();
        int rows = board.length, cols = board[0].length;
        for (int r = 0; r < rows; r++) {
            for (int c = 0; c < cols; c++) {
                int idx = board[r][c] - 'a';
                if (root.kids[idx] != null) dfs(board, r, c, root, found);
            }
        }
        Collections.sort(found);
        return found;
    }

    private void dfs(char[][] board, int r, int c, Node node, List<String> found) {
        char ch = board[r][c];
        if (ch == '#') return;
        Node next = node.kids[ch - 'a'];
        if (next == null) return;
        if (next.word != null) { found.add(next.word); next.word = null; }
        board[r][c] = '#';
        int[][] dirs = {{1,0},{-1,0},{0,1},{0,-1}};
        for (int[] d : dirs) {
            int nr = r + d[0], nc = c + d[1];
            if (nr >= 0 && nr < board.length && nc >= 0 && nc < board[0].length) {
                dfs(board, nr, nc, next, found);
            }
        }
        board[r][c] = ch;
    }
}`,
