        code: `func intersection(nums1 []int, nums2 []int) []int {
    s1 := map[int]struct{}{}
    for _, x := range nums1 { s1[x] = struct{}{} }
    seen := map[int]struct{}{}
    out := []int{}
    for _, x := range nums2 {
        if _, ok := s1[x]; ok {
            if _, dup := seen[x]; !dup {
                out = append(out, x)
                seen[x] = struct{}{}
            }
        }
    }
    sort.Ints(out)
    return out
}`,
        complexity: { time: 'O(m + n)', space: 'O(min(m, n))' },
        approach: 'map[int]struct{} for sets. Sort result for deterministic comparison.',
