  if (n < 3) return 0;
  const sieve = new Uint8Array(n).fill(1);
  sieve[0] = sieve[1] = 0;
  const limit = Math.sqrt(n) | 0;
  for (let i = 2; i <= limit; i++) {
    if (sieve[i]) {
      for (let j = i * i; j < n; j += i) sieve[j] = 0;
    }
  }
  let count = 0;
  for (let i = 2; i < n; i++) if (sieve[i]) count++;
  return count;
