        code: `#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int countPrimes(int n) {
    if (n < 3) return 0;
    char* composite = (char*)calloc(n, 1);
    for (int i = 2; (long long) i * i < n; i++) {
        if (!composite[i]) {
            for (int j = i * i; j < n; j += i) composite[j] = 1;
        }
    }
    int count = 0;
    for (int i = 2; i < n; i++) if (!composite[i]) count++;
    free(composite);
    return count;
}`,
        complexity: { time: 'O(n log log n)', space: 'O(n)' },
        approach: 'calloc zeros memory; char as boolean.',
