        code: `#include <stdio.h>
#include <stdlib.h>

int minDepth(struct TreeNode* root) {
    if (!root) return 0;
    struct TreeNode* nodes[10000];
    int depths[10000];
    int head = 0, tail = 0;
    nodes[tail] = root;
    depths[tail++] = 1;
    while (head < tail) {
        struct TreeNode* node = nodes[head];
        int d = depths[head++];
        if (!node->left && !node->right) return d;
        if (node->left) { nodes[tail] = node->left; depths[tail++] = d + 1; }
        if (node->right) { nodes[tail] = node->right; depths[tail++] = d + 1; }
    }
    return 0;
}`,
        complexity: { time: 'O(n)', space: 'O(w)' },
        approach: 'Parallel arrays for node + depth.',
